mapper.update:
UPDATE vip_order
SET order_no = #{orderNo},
    toc_user_id = #{tocUserId},
    plan_id = #{planId},
    order_status = #{orderStatus},
    amount = #{amount},
    paid_at = #{paidAt},
    channel = #{channel}
WHERE tenant_id = #{tenantId}
  AND id = #{id}

